1	<!DOCTYPE html>
2	<html lang="en">
3	<head>
4	<meta charset="UTF-8">
5	<meta name="viewport" content="width=device-width, initial-scale=1.0">
6	<title>Voice of Customer — April 2025</title>
7	<link href="https://fonts.googleapis.com/css2?family=Playfair+Display:wght@400;600;700&family=IBM+Plex+Mono:wght@400;500&family=IBM+Plex+Sans:wght@300;400;500&display=swap" rel="stylesheet">
8	<style>
9	  :root {
10	    --ink: #0f0f0f;
11	    --ink-mid: #3a3a3a;
12	    --ink-light: #7a7a7a;
13	    --ink-faint: #d0d0d0;
14	    --paper: #f8f6f2;
15	    --accent: #1a1a1a;
16	    --rule: 1px solid #0f0f0f;
17	    --rule-light: 1px solid #d0d0d0;
18	  }
19	
20	  * { margin: 0; padding: 0; box-sizing: border-box; }
21	
22	  @page {
23	    size: letter;
24	    margin: 0;
25	  }
26	
27	  body {
28	    background: #e8e6e0;
29	    display: flex;
30	    align-items: center;
31	    justify-content: center;
32	    min-height: 100vh;
33	    padding: 32px;
34	    font-family: 'IBM Plex Sans', sans-serif;
35	  }
36	
37	  .page {
38	    background: var(--paper);
39	    width: 816px;
40	    min-height: 1056px;
41	    padding: 52px 52px 44px;
42	    position: relative;
43	    box-shadow: 0 8px 48px rgba(0,0,0,0.18);
44	  }
45	
46	  /* ── HEADER ── */
47	  .header {
48	    border-top: 3px solid var(--ink);
49	    border-bottom: var(--rule);
50	    padding: 14px 0 12px;
51	    display: flex;
52	    align-items: baseline;
53	    justify-content: space-between;
54	    margin-bottom: 28px;
55	  }
56	  .header-left {
57	    display: flex;
58	    align-items: baseline;
59	    gap: 18px;
60	  }
61	  .title {
62	    font-family: 'Playfair Display', serif;
63	    font-size: 28px;
64	    font-weight: 700;
65	    letter-spacing: -0.5px;
66	    color: var(--ink);
67	  }
68	  .subtitle {
69	    font-family: 'IBM Plex Mono', monospace;
70	    font-size: 10px;
71	    color: var(--ink-light);
72	    letter-spacing: 2px;
73	    text-transform: uppercase;
74	  }
75	  .header-right {
76	    text-align: right;
77	  }
78	  .month-label {
79	    font-family: 'Playfair Display', serif;
80	    font-size: 13px;
81	    font-weight: 600;
82	    color: var(--ink);
83	    letter-spacing: 0.5px;
84	  }
85	  .dept-label {
86	    font-family: 'IBM Plex Mono', monospace;
87	    font-size: 9px;
88	    color: var(--ink-light);
89	    letter-spacing: 1.5px;
90	    text-transform: uppercase;
91	    margin-top: 2px;
92	  }
93	
94	  /* ── STATS ROW ── */
95	  .stats-row {
96	    display: grid;
97	    grid-template-columns: repeat(4, 1fr);
98	    gap: 0;
99	    border: var(--rule);
100	    margin-bottom: 28px;
101	  }
102	  .stat {
103	    padding: 14px 16px;
104	    border-right: var(--rule);
105	  }
106	  .stat:last-child { border-right: none; }
107	  .stat-num {
108	    font-family: 'Playfair Display', serif;
109	    font-size: 30px;
110	    font-weight: 700;
111	    color: var(--ink);
112	    line-height: 1;
113	    margin-bottom: 4px;
114	  }
115	  .stat-num.placeholder {
116	    color: var(--ink-faint);
117	    font-style: italic;
118	    font-size: 22px;
119	  }
120	  .stat-label {
121	    font-family: 'IBM Plex Mono', monospace;
122	    font-size: 8.5px;
123	    color: var(--ink-light);
124	    letter-spacing: 1.5px;
125	    text-transform: uppercase;
126	    line-height: 1.4;
127	  }
128	  .stat-delta {
129	    font-family: 'IBM Plex Mono', monospace;
130	    font-size: 9px;
131	    color: var(--ink-mid);
132	    margin-top: 3px;
133	  }
134	
135	  /* ── MAIN GRID ── */
136	  .main-grid {
137	    display: grid;
138	    grid-template-columns: 1fr 212px;
139	    gap: 28px;
140	    align-items: start;
141	  }
142	
143	  /* ── LEFT COLUMN ── */
144	  .left-col {}
145	
146	  .section-label {
147	    font-family: 'IBM Plex Mono', monospace;
148	    font-size: 8.5px;
149	    letter-spacing: 2px;
150	    text-transform: uppercase;
151	    color: var(--ink-light);
152	    margin-bottom: 10px;
153	  }
154	
155	  /* Reasons block */
156	  .reasons-block {
157	    margin-bottom: 22px;
158	  }
159	  .reasons-title {
160	    font-family: 'Playfair Display', serif;
161	    font-size: 13px;
162	    font-weight: 600;
163	    color: var(--ink);
164	    margin-bottom: 10px;
165	    padding-bottom: 6px;
166	    border-bottom: var(--rule);
167	  }
168	  .reason-row {
169	    display: grid;
170	    grid-template-columns: 22px 1fr 64px 56px;
171	    align-items: center;
172	    padding: 8px 0;
173	    border-bottom: var(--rule-light);
174	    gap: 10px;
175	  }
176	  .reason-row:last-child { border-bottom: none; }
177	  .reason-num {
178	    font-family: 'IBM Plex Mono', monospace;
179	    font-size: 9px;
180	    color: var(--ink-light);
181	  }
182	  .reason-text {
183	    font-family: 'IBM Plex Sans', sans-serif;
184	    font-size: 11.5px;
185	    font-weight: 500;
186	    color: var(--ink);
187	    line-height: 1.3;
188	  }
189	  .reason-sub {
190	    font-family: 'IBM Plex Sans', sans-serif;
191	    font-size: 9.5px;
192	    color: var(--ink-light);
193	    margin-top: 1px;
194	  }
195	  .reason-bar-wrap {
196	    height: 4px;
197	    background: var(--ink-faint);
198	    border-radius: 2px;
199	    overflow: hidden;
200	  }
201	  .reason-bar {
202	    height: 100%;
203	    background: var(--ink);
204	    border-radius: 2px;
205	  }
206	  .reason-pct {
207	    font-family: 'IBM Plex Mono', monospace;
208	    font-size: 10px;
209	    font-weight: 500;
210	    color: var(--ink);
211	    text-align: right;
212	  }
213	
214	  /* Two-col sub-section */
215	  .two-col {
216	    display: grid;
217	    grid-template-columns: 1fr 1fr;
218	    gap: 16px;
219	    margin-bottom: 22px;
220	  }
221	  .sub-card {
222	    border: var(--rule-light);
223	    padding: 12px 14px;
224	  }
225	  .sub-card-title {
226	    font-family: 'IBM Plex Mono', monospace;
227	    font-size: 8.5px;
228	    letter-spacing: 1.5px;
229	    text-transform: uppercase;
230	    color: var(--ink-light);
231	    border-bottom: var(--rule-light);
232	    padding-bottom: 6px;
233	    margin-bottom: 8px;
234	  }
235	  .sub-card-item {
236	    font-family: 'IBM Plex Sans', sans-serif;
237	    font-size: 10.5px;
238	    color: var(--ink-mid);
239	    line-height: 1.5;
240	    padding: 3px 0;
241	    border-bottom: var(--rule-light);
242	    display: flex;
243	    align-items: flex-start;
244	    gap: 6px;
245	  }
246	  .sub-card-item:last-child { border-bottom: none; }
247	  .sub-card-item::before {
248	    content: '—';
249	    color: var(--ink-faint);
250	    font-size: 9px;
251	    flex-shrink: 0;
252	    margin-top: 1px;
253	  }
254	
255	  /* Tactics */
256	  .tactics-block {}
257	  .tactic-item {
258	    display: flex;
259	    align-items: flex-start;
260	    gap: 10px;
261	    padding: 7px 0;
262	    border-bottom: var(--rule-light);
263	  }
264	  .tactic-item:last-child { border-bottom: none; }
265	  .tactic-tag {
266	    font-family: 'IBM Plex Mono', monospace;
267	    font-size: 8px;
268	    letter-spacing: 1px;
269	    text-transform: uppercase;
270	    background: var(--ink);
271	    color: var(--paper);
272	    padding: 2px 5px;
273	    flex-shrink: 0;
274	    margin-top: 1px;
275	  }
276	  .tactic-text {
277	    font-family: 'IBM Plex Sans', sans-serif;
278	    font-size: 10.5px;
279	    color: var(--ink-mid);
280	    line-height: 1.4;
281	  }
282	
283	  /* ── RIGHT SIDEBAR ── */
284	  .right-col {
285	    display: flex;
286	    flex-direction: column;
287	    gap: 16px;
288	  }
289	
290	  .sidebar-box {
291	    border: var(--rule);
292	    padding: 14px;
293	  }
294	  .sidebar-box-title {
295	    font-family: 'Playfair Display', serif;
296	    font-size: 12px;
297	    font-weight: 600;
298	    color: var(--ink);
299	    margin-bottom: 8px;
300	    padding-bottom: 6px;
301	    border-bottom: var(--rule);
302	  }
303	
304	  /* Calendar events */
305	  .cal-item {
306	    padding: 7px 0;
307	    border-bottom: var(--rule-light);
308	  }
309	  .cal-item:last-child { border-bottom: none; }
310	  .cal-date {
311	    font-family: 'IBM Plex Mono', monospace;
312	    font-size: 8px;
313	    color: var(--ink-light);
314	    letter-spacing: 1px;
315	    text-transform: uppercase;
316	    margin-bottom: 2px;
317	  }
318	  .cal-event {
319	    font-family: 'IBM Plex Sans', sans-serif;
320	    font-size: 10px;
321	    font-weight: 500;
322	    color: var(--ink);
323	    line-height: 1.35;
324	  }
325	  .cal-desc {
326	    font-family: 'IBM Plex Sans', sans-serif;
327	    font-size: 9px;
328	    color: var(--ink-light);
329	    margin-top: 2px;
330	    line-height: 1.35;
331	  }
332	
333	  /* Teams */
334	  .team-grid {
335	    display: flex;
336	    flex-wrap: wrap;
337	    gap: 5px;
338	  }
339	  .team-pill {
340	    font-family: 'IBM Plex Mono', monospace;
341	    font-size: 8.5px;
342	    letter-spacing: 1px;
343	    text-transform: uppercase;
344	    border: var(--rule-light);
345	    padding: 4px 7px;
346	    color: var(--ink-mid);
347	  }
348	
349	  /* Outcomes */
350	  .outcome-item {
351	    padding: 6px 0;
352	    border-bottom: var(--rule-light);
353	  }
354	  .outcome-item:last-child { border-bottom: none; }
355	  .outcome-label {
356	    font-family: 'IBM Plex Mono', monospace;
357	    font-size: 8px;
358	    color: var(--ink-light);
359	    letter-spacing: 1px;
360	    text-transform: uppercase;
361	    margin-bottom: 2px;
362	  }
363	  .outcome-text {
364	    font-family: 'IBM Plex Sans', sans-serif;
365	    font-size: 9.5px;
366	    color: var(--ink-mid);
367	    line-height: 1.4;
368	  }
369	
370	  /* ── FOOTER ── */
371	  .footer {
372	    border-top: var(--rule);
373	    margin-top: 24px;
374	    padding-top: 10px;
375	    display: flex;
376	    justify-content: space-between;
377	    align-items: center;
378	  }
379	  .footer-note {
380	    font-family: 'IBM Plex Mono', monospace;
381	    font-size: 8.5px;
382	    color: var(--ink-light);
383	    letter-spacing: 1px;
384	  }
385	  .footer-logo {
386	    font-family: 'Playfair Display', serif;
387	    font-size: 10px;
388	    color: var(--ink-faint);
389	    letter-spacing: 1px;
390	    font-style: italic;
391	  }
392	
393	  @media print {
394	    body { background: white; padding: 0; }
395	    .page { box-shadow: none; width: 100%; min-height: auto; }
396	  }
397	</style>
398	</head>
399	<body>
400	<div class="page">
401	
402	  <!-- HEADER -->
403	  <div class="header">
404	    <div class="header-left">
405	      <div class="title">Voice of Customer</div>
406	      <div class="subtitle">Executive Summary</div>
407	    </div>
408	    <div class="header-right">
409	      <div class="month-label">April 2025</div>
410	      <div class="dept-label">Customer Insights · Confidential</div>
411	    </div>
412	  </div>
413	
414	  <!-- STATS ROW -->
415	  <div class="stats-row">
416	    <div class="stat">
417	      <div class="stat-num placeholder">###</div>
418	      <div class="stat-label">Total<br>Cancellations</div>
419	      <div class="stat-delta">vs. _____ prior month</div>
420	    </div>
421	    <div class="stat">
422	      <div class="stat-num placeholder">##%</div>
423	      <div class="stat-label">Churn<br>Rate</div>
424	      <div class="stat-delta">vs. _____ prior month</div>
425	    </div>
426	    <div class="stat">
427	      <div class="stat-num placeholder">###</div>
428	      <div class="stat-label">Survey<br>Responses</div>
429	      <div class="stat-delta">__ % response rate</div>
430	    </div>
431	    <div class="stat">
432	      <div class="stat-num placeholder">##%</div>
433	      <div class="stat-label">Avg App<br>Review Score</div>
434	      <div class="stat-delta">__ reviews analyzed</div>
435	    </div>
436	  </div>
437	
438	  <!-- MAIN GRID -->
439	  <div class="main-grid">
440	    <div class="left-col">
441	
442	      <!-- TOP CANCELLATION REASONS -->
443	      <div class="reasons-block">
444	        <div class="reasons-title">Top Reasons Customers Are Leaving / Flagging Concerns</div>
445	
446	        <div class="reason-row">
447	          <div class="reason-num">01</div>
448	          <div>
449	            <div class="reason-text">Pricing &amp; Value Perception</div>
450	            <div class="reason-sub">Cost too high relative to perceived benefit</div>
451	          </div>
452	          <div class="reason-bar-wrap"><div class="reason-bar" style="width:85%"></div></div>
453	          <div class="reason-pct">##%</div>
454	        </div>
455	
456	        <div class="reason-row">
457	          <div class="reason-num">02</div>
458	          <div>
459	            <div class="reason-text">Product / Feature Gaps</div>
460	            <div class="reason-sub">Missing functionality or unmet use-case needs</div>
461	          </div>
462	          <div class="reason-bar-wrap"><div class="reason-bar" style="width:68%"></div></div>
463	          <div class="reason-pct">##%</div>
464	        </div>
465	
466	        <div class="reason-row">
467	          <div class="reason-num">03</div>
468	          <div>
469	            <div class="reason-text">App Performance &amp; Bugs</div>
470	            <div class="reason-sub">Crashes, slow load times, UX friction</div>
471	          </div>
472	          <div class="reason-bar-wrap"><div class="reason-bar" style="width:52%"></div></div>
473	          <div class="reason-pct">##%</div>
474	        </div>
475	
476	        <div class="reason-row">
477	          <div class="reason-num">04</div>
478	          <div>
479	            <div class="reason-text">Competitive Alternative</div>
480	            <div class="reason-sub">Switched to a specific competitor</div>
481	          </div>
482	          <div class="reason-bar-wrap"><div class="reason-bar" style="width:40%"></div></div>
483	          <div class="reason-pct">##%</div>
484	        </div>
485	
486	        <div class="reason-row">
487	          <div class="reason-num">05</div>
488	          <div>
489	            <div class="reason-text">Onboarding &amp; Support Experience</div>
490	            <div class="reason-sub">Difficult setup, slow response times</div>
491	          </div>
492	          <div class="reason-bar-wrap"><div class="reason-bar" style="width:29%"></div></div>
493	          <div class="reason-pct">##%</div>
494	        </div>
495	
496	        <div class="reason-row">
497	          <div class="reason-num">06</div>
498	          <div>
499	            <div class="reason-text">Business Change / No Longer Needed</div>
500	            <div class="reason-sub">Budget cuts, company pivot, seasonal use</div>
501	          </div>
502	          <div class="reason-bar-wrap"><div class="reason-bar" style="width:18%"></div></div>
503	          <div class="reason-pct">##%</div>
504	        </div>
505	      </div>
506	
507	      <!-- APP REVIEWS + SURVEYS -->
508	      <div class="two-col">
509	        <div class="sub-card">
510	          <div class="sub-card-title">App Review Themes</div>
511	          <div class="sub-card-item">[ Replace with top positive theme ]</div>
512	          <div class="sub-card-item">[ Replace with top positive theme ]</div>
513	          <div class="sub-card-item">[ Replace with top negative theme ]</div>
514	          <div class="sub-card-item">[ Replace with top negative theme ]</div>
515	        </div>
516	        <div class="sub-card">
517	          <div class="sub-card-title">General Survey Themes</div>
518	          <div class="sub-card-item">[ Replace with recurring request ]</div>
519	          <div class="sub-card-item">[ Replace with recurring request ]</div>
520	          <div class="sub-card-item">[ Replace with pain point surfaced ]</div>
521	          <div class="sub-card-item">[ Replace with notable compliment ]</div>
522	        </div>
523	      </div>
524	
525	      <!-- TACTICS IN MOTION -->
526	      <div class="section-label">Response Tactics in Motion</div>
527	      <div class="tactics-block">
528	        <div class="tactic-item">
529	          <span class="tactic-tag">Pricing</span>
530	          <div class="tactic-text">[ Describe pricing adjustment or packaging initiative underway ]</div>
531	        </div>
532	        <div class="tactic-item">
533	          <span class="tactic-tag">Product</span>
534	          <div class="tactic-text">[ Describe feature build or roadmap acceleration in response to feedback ]</div>
535	        </div>
536	        <div class="tactic-item">
537	          <span class="tactic-tag">Tech</span>
538	          <div class="tactic-text">[ Describe bug fix sprint or performance improvement initiative ]</div>
539	        </div>
540	        <div class="tactic-item">
541	          <span class="tactic-tag">CS</span>
542	          <div class="tactic-text">[ Describe onboarding or support workflow changes ]</div>
543	        </div>
544	      </div>
545	
546	    </div><!-- /left-col -->
547	
548	    <!-- RIGHT SIDEBAR -->
549	    <div class="right-col">
550	
551	      <!-- UPCOMING CALENDAR -->
552	      <div class="sidebar-box">
553	        <div class="sidebar-box-title">Upcoming</div>
554	
555	        <div class="cal-item">
556	          <div class="cal-date">May · Week 1</div>
557	          <div class="cal-event">Annual Customer Survey Launch</div>
558	          <div class="cal-desc">Full send to active base; closes May 28</div>
559	        </div>
560	
561	        <div class="cal-item">
562	          <div class="cal-date">May · Week 2</div>
563	          <div class="cal-event">Persona Segmentation Kickoff</div>
564	          <div class="cal-desc">Data pull + clustering workshop with Product &amp; Growth</div>
565	        </div>
566	
567	        <div class="cal-item">
568	          <div class="cal-date">May · Week 3</div>
569	          <div class="cal-event">Mid-Survey Pulse Check</div>
570	          <div class="cal-desc">Response rate review; reminder sequence if needed</div>
571	        </div>
572	
573	        <div class="cal-item">
574	          <div class="cal-date">June · Week 1</div>
575	          <div class="cal-event">Segmentation Readout</div>
576	          <div class="cal-desc">Present persona outcomes to leadership</div>
577	        </div>
578	      </div>
579	
580	      <!-- EXPECTED OUTCOMES -->
581	      <div class="sidebar-box">
582	        <div class="sidebar-box-title">Expected Outcomes</div>
583	        <div class="outcome-item">
584	          <div class="outcome-label">Annual Survey</div>
585	          <div class="outcome-text">Baseline NPS, feature priority rankings, churn risk signals</div>
586	        </div>
587	        <div class="outcome-item">
588	          <div class="outcome-label">Persona Segmentation</div>
589	          <div class="outcome-text">3–5 defined customer personas to inform roadmap, messaging &amp; pricing tiers</div>
590	        </div>
591	      </div>
592	
593	      <!-- PARTNERING TEAMS -->
594	      <div class="sidebar-box">
595	        <div class="sidebar-box-title">Partnering Teams</div>
596	        <div class="team-grid">
597	          <div class="team-pill">Growth</div>
598	          <div class="team-pill">Sales</div>
599	          <div class="team-pill">Operations</div>
600	          <div class="team-pill">Tech</div>
601	          <div class="team-pill">Product</div>
602	        </div>
603	      </div>
604	
605	    </div><!-- /right-col -->
606	  </div><!-- /main-grid -->
607	
608	  <!-- FOOTER -->
609	  <div class="footer">
610	    <div class="footer-note">April 2025 · Voice of Customer · Internal Use Only</div>
611	    <div class="footer-logo">Customer Insights</div>
612	  </div>
613	
614	</div>
615	</body>
616	</html>
617

